--
-- Table structure for table `interventiontime`
--

DROP TABLE IF EXISTS `interventiontime`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `interventiontime` (
  `intervention_id` int NOT NULL AUTO_INCREMENT COMMENT '干预方式ID',
  `patient_id` int NOT NULL COMMENT '患者ID,外键',
  `admission_date` date NOT NULL COMMENT '接诊日期',
  `admission_time` varchar(4) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '接诊时间',
  `peripheral` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '外周',
  `iv_line` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '深静脉',
  `central_access` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '骨通道',
  `nasal_pipe` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鼻导管',
  `face_mask` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '面罩',
  `endotracheal_tube` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '气管插管',
  `ventilator` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '呼吸机',
  `cpr` varchar(2) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '心肺复苏(是/否)',
  `cpr_start_time` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '心肺复苏开始时间',
  `cpr_end_time` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '心肺复苏结束时间',
  `ultrasound` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'B超',
  `ct` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'CT',
  `tourniquet` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '止血带',
  `blood_draw` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '采血',
  `catheter` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '导尿',
  `gastric_tube` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '胃管',
  `transfusion` varchar(2) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '输血(是/否)',
  `transfusion_start` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '输血开始时间',
  `transfusion_end` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '输血结束时间',
  `leave_surgery_time` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '离开抢救室时间',
  `leave_surgery_date` date DEFAULT NULL COMMENT '离开抢救室日期',
  `patient_destination` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '病人去向',
  `death` varchar(2) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '死亡(是/否)',
  `death_date` date DEFAULT NULL COMMENT '死亡日期',
  `death_time` varchar(4) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '死亡时间',
  `departure_destination` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '离开就诊室去向',
  `is_dead` tinyint(1) DEFAULT '0' COMMENT '是否死亡',
  PRIMARY KEY (`intervention_id`),
  KEY `fk_intervention_patient` (`patient_id`),
  CONSTRAINT `fk_intervention_patient` FOREIGN KEY (`patient_id`) REFERENCES `patient` (`patient_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2241 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='干预方式时间表';
/*!40101 SET character_set_client = @saved_cs_client */;

