--
-- Table structure for table `iss_patient_injury_severity`
--

DROP TABLE IF EXISTS `iss_patient_injury_severity`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `iss_patient_injury_severity` (
  `injury_id` int NOT NULL AUTO_INCREMENT,
  `patient_id` int NOT NULL,
  `head_neck` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '头颈部伤情等级，支持"2|3"格式',
  `face` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '面部伤情等级，支持"2|3"格式',
  `chest` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '胸部伤情等级，支持"2|3"格式',
  `abdomen` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '腹部伤情等级，支持"2|3"格式',
  `limbs` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '四肢伤情等级，支持"2|3"格式',
  `body` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '体表伤情等级，支持"2|3"格式',
  `iss_score` int DEFAULT NULL COMMENT 'ISS评分',
  `head_neck_details` text COLLATE utf8mb4_unicode_ci COMMENT '头颈部详细伤情',
  `face_details` text COLLATE utf8mb4_unicode_ci COMMENT '面部详细伤情',
  `chest_details` text COLLATE utf8mb4_unicode_ci COMMENT '胸部详细伤情',
  `abdomen_details` text COLLATE utf8mb4_unicode_ci COMMENT '腹部详细伤情',
  `limbs_details` text COLLATE utf8mb4_unicode_ci COMMENT '四肢详细伤情',
  `body_details` text COLLATE utf8mb4_unicode_ci COMMENT '体表详细伤情',
  `has_details` tinyint(1) DEFAULT '0' COMMENT '是否有详细伤情信息',
  PRIMARY KEY (`injury_id`),
  KEY `fk_iss_patient` (`patient_id`),
  CONSTRAINT `fk_iss_patient` FOREIGN KEY (`patient_id`) REFERENCES `patient` (`patient_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4384 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='创伤等级ISS表';
/*!40101 SET character_set_client = @saved_cs_client */;

